/*
 * NOT generated by Speakeasy — hand-written OAuth wrapper.
 *
 * Adds OAuth 2.1 (auth-code + PKCE + Dynamic Client Registration) to the remote
 * MCP server so the Claude app (and any OAuth MCP client) can connect, while the
 * existing static-header passthrough keeps working for Cursor / Claude Code.
 *
 * Endpoints:
 *   /mcp            -> OAuth-protected MCP (apiRoute, prefix match). Claude discovers this.
 *   /direct/mcp     -> header passthrough (bearer: / latitude-api-key:); kept off
 *                      the "/mcp" prefix so the OAuth guard doesn't swallow it.
 *   /sse            -> header passthrough (legacy SSE)
 *   /authorize      -> bridges Claude's redirect flow to Latitude's cli_sessions
 *   /authorize/poll -> server-side poll of the cli_session; completes the grant
 *   /token,/register,/.well-known/*  -> served by workers-oauth-provider
 *
 * The OAuth grant stores the user's Latitude API key (minted by the dashboard
 * approval) in `props.bearer`; the McpAgent's getSDK() reads `this.props.bearer`,
 * so the same agent works for both auth paths. Requires the wrangler.toml `main`
 * to point here and an OAUTH_KV namespace binding.
 */

import OAuthProvider from "@cloudflare/workers-oauth-provider";
import type { AuthRequest, OAuthHelpers } from "@cloudflare/workers-oauth-provider";
import { landingPage } from "../landing-page.js";
// Re-use the Speakeasy-generated Durable Object (McpAgent) unchanged.
import { LatitudeshMCP } from "./cloudflare-worker.js";

// The Durable Object class must be exported from the worker entrypoint so the
// `LATITUDESH_MCP` binding resolves.
export { LatitudeshMCP };

const LATITUDE_API_BASE = "https://api.latitude.sh";
const LOGIN_TTL_SECONDS = 600;
const MCP_BINDING = "LATITUDESH_MCP";

interface Bindings {
  OAUTH_KV: KVNamespace;
  OAUTH_PROVIDER: OAuthHelpers;
  LATITUDESH_MCP: DurableObjectNamespace;
  ASSETS: Fetcher;
}

interface LoginState {
  oauthReqInfo: AuthRequest;
  sessionId: string;
  secret: string;
}

interface CliSession {
  id: string;
  secret: string;
  user_code: string;
  authorize_url: string;
}

function json(body: unknown, status = 200): Response {
  return new Response(JSON.stringify(body), {
    status,
    headers: { "content-type": "application/json" },
  });
}

// --- Latitude cli_sessions bridge -------------------------------------------

async function createCliSession(): Promise<CliSession> {
  const res = await fetch(`${LATITUDE_API_BASE}/auth/cli_sessions`, {
    method: "POST",
    headers: { "content-type": "application/json", accept: "application/json" },
    body: JSON.stringify({
      client_name: "Latitude MCP",
      client_version: "0.2.3",
    }),
  });
  if (!res.ok) {
    throw new Error(`cli_sessions create failed: ${res.status} ${await res.text()}`);
  }
  const body = (await res.json()) as { data: CliSession };
  return body.data;
}

// Returns the approved payload (with api_key) or null while still pending.
async function pollCliSession(
  sessionId: string,
  secret: string,
): Promise<{ apiKey: string; userId: string; email: string; teamSlug: string } | null> {
  const res = await fetch(`${LATITUDE_API_BASE}/auth/cli_sessions/${sessionId}`, {
    headers: { "X-CLI-Secret": secret, accept: "application/json" },
  });
  // 404 right after create = not yet propagated; 410 = already consumed.
  // Both are transient/terminal but the browser keeps polling within the TTL.
  if (!res.ok) return null;
  const body = (await res.json()) as {
    data: {
      status: string;
      api_key?: { token: string };
      user?: { id: string; email: string };
      team?: { slug: string };
    };
  };
  const data = body.data;
  if (data.status !== "approved" || !data.api_key?.token) return null;
  return {
    apiKey: data.api_key.token,
    userId: data.user?.id ?? "latitude-user",
    email: data.user?.email ?? "",
    teamSlug: data.team?.slug ?? "",
  };
}

// --- OAuth /authorize handlers ----------------------------------------------

async function handleAuthorize(request: Request, env: Bindings): Promise<Response> {
  const oauthReqInfo = await env.OAUTH_PROVIDER.parseAuthRequest(request);
  if (!oauthReqInfo.clientId) {
    return new Response("Invalid authorization request", { status: 400 });
  }

  const session = await createCliSession();
  const loginId = crypto.randomUUID();
  const state: LoginState = {
    oauthReqInfo,
    sessionId: session.id,
    secret: session.secret,
  };
  await env.OAUTH_KV.put(`login:${loginId}`, JSON.stringify(state), {
    expirationTtl: LOGIN_TTL_SECONDS,
  });

  return new Response(renderAuthorizePage(session.authorize_url, session.user_code, loginId), {
    headers: { "content-type": "text/html; charset=utf-8" },
  });
}

async function handlePoll(request: Request, env: Bindings): Promise<Response> {
  const loginId = new URL(request.url).searchParams.get("login");
  if (!loginId) return json({ status: "error" }, 400);

  const raw = await env.OAUTH_KV.get(`login:${loginId}`);
  if (!raw) return json({ status: "expired" });
  const state = JSON.parse(raw) as LoginState;

  const approved = await pollCliSession(state.sessionId, state.secret);
  if (!approved) return json({ status: "pending" });

  const { redirectTo } = await env.OAUTH_PROVIDER.completeAuthorization({
    request: state.oauthReqInfo,
    userId: approved.userId,
    metadata: { email: approved.email, team: approved.teamSlug },
    scope: state.oauthReqInfo.scope ?? [],
    // Read by LatitudeshMCP.getSDK() as `this.props.bearer`.
    props: { bearer: approved.apiKey, email: approved.email, teamSlug: approved.teamSlug },
  });

  await env.OAUTH_KV.delete(`login:${loginId}`);
  return json({ status: "approved", redirectTo });
}

function renderAuthorizePage(authorizeUrl: string, userCode: string, loginId: string): string {
  const data = JSON.stringify({ authorizeUrl, loginId });
  return `<!doctype html>
<html lang="en">
<head>
<meta charset="utf-8" />
<meta name="viewport" content="width=device-width, initial-scale=1" />
<title>Authorize Latitude MCP</title>
<style>
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif; background:#0f1115; color:#e6e8eb; display:flex; min-height:100vh; align-items:center; justify-content:center; margin:0; }
  .card { max-width:440px; padding:40px; text-align:center; }
  h1 { font-size:20px; margin:0 0 8px; }
  p { color:#9aa0a6; line-height:1.5; }
  .btn { display:inline-block; margin:24px 0 16px; padding:12px 24px; background:#3b82f6; color:#fff; text-decoration:none; border-radius:8px; font-weight:600; }
  .code { font-family: ui-monospace, monospace; font-size:22px; letter-spacing:2px; background:#1a1d24; padding:8px 14px; border-radius:6px; display:inline-block; }
  .status { margin-top:20px; font-size:14px; color:#9aa0a6; }
</style>
</head>
<body>
  <div class="card">
    <h1>Authorize Latitude MCP</h1>
    <p>Approve this connection in your Latitude dashboard. Confirm this code matches:</p>
    <div class="code">${userCode}</div>
    <br />
    <a class="btn" id="approve" href="${authorizeUrl}" target="_blank" rel="noopener">Continue to Latitude →</a>
    <p class="status" id="status">Waiting for approval…</p>
  </div>
<script>
  const cfg = ${data};
  // Best-effort: pop the dashboard automatically; the button is the fallback.
  try { window.open(cfg.authorizeUrl, "_blank", "noopener"); } catch (e) {}
  const statusEl = document.getElementById("status");
  async function poll() {
    try {
      const r = await fetch("/authorize/poll?login=" + encodeURIComponent(cfg.loginId));
      const j = await r.json();
      if (j.status === "approved") { statusEl.textContent = "Approved — redirecting…"; window.location = j.redirectTo; return; }
      if (j.status === "expired") { statusEl.textContent = "This login expired. Close this tab and try again."; return; }
    } catch (e) {}
    setTimeout(poll, 2000);
  }
  setTimeout(poll, 2000);
</script>
</body>
</html>`;
}

// --- Header-passthrough MCP (Cursor / Claude Code) --------------------------

function headerProps(request: Request): Record<string, string> {
  const props: Record<string, string> = {};
  for (const [key, value] of request.headers.entries()) props[key.toLowerCase()] = value;
  return props;
}

// --- defaultHandler: everything not on the OAuth apiRoute -------------------

const defaultHandler = {
  async fetch(request: Request, env: Bindings, ctx: ExecutionContext): Promise<Response> {
    const url = new URL(request.url);

    if (url.pathname === "/authorize") return handleAuthorize(request, env);
    if (url.pathname === "/authorize/poll") return handlePoll(request, env);

    // Header passthrough (static Latitude API key in `bearer:`/`latitude-api-key:`).
    if (url.pathname === "/sse" || url.pathname.startsWith("/sse/")) {
      (ctx as unknown as { props: Record<string, string> }).props = headerProps(request);
      return LatitudeshMCP.serveSSE("/sse", { binding: MCP_BINDING }).fetch(request, env, ctx);
    }
    // NB: must NOT live under the "/mcp" prefix — OAuthProvider's apiRoute is a
    // prefix match, so anything starting with "/mcp" is OAuth-guarded.
    if (url.pathname === "/direct/mcp") {
      (ctx as unknown as { props: Record<string, string> }).props = headerProps(request);
      return LatitudeshMCP.serve("/direct/mcp", { binding: MCP_BINDING }).fetch(request, env, ctx);
    }

    if (url.pathname === "/") return landingPage(request);

    // .dxt -> .mcpb backwards-compat redirect.
    if (url.pathname.endsWith(".dxt")) {
      const newUrl = new URL(url);
      newUrl.pathname = url.pathname.replace(/\.dxt$/, ".mcpb");
      return Response.redirect(newUrl.toString(), 301);
    }

    // Static asset fallback (mcp bundle download).
    const response = await env.ASSETS.fetch(request);
    if (response.ok) {
      return new Response(response.body, {
        headers: {
          "Content-Type": "application/octet-stream",
          "Content-Disposition": 'attachment; filename="mcp-server.mcpb"',
          "Cache-Control": "public, max-age=3600",
        },
      });
    }
    return response;
  },
};

export default new OAuthProvider({
  apiRoute: "/mcp",
  // OAuth-protected MCP. OAuthProvider sets ctx.props from the grant before
  // invoking this, so LatitudeshMCP.getSDK() finds `this.props.bearer`.
  apiHandler: LatitudeshMCP.serve("/mcp", { binding: MCP_BINDING }) as never,
  defaultHandler: defaultHandler as never,
  authorizeEndpoint: "/authorize",
  tokenEndpoint: "/token",
  clientRegistrationEndpoint: "/register",
  scopesSupported: ["mcp"],
});
